# Scratch: 和"如果那么"积木一样
天气 = input("今天天气怎么样？(晴天/下雨)：")
if 天气 == "晴天":
    print("出去玩吧！")
else:
    print("在家写程序吧！")

# Scratch: 和"如果那么 否则如果那么"积木一样
小时 = int(input("现在几点？(0-23)："))
if 小时 < 10:
    print("早上好！")
elif 小时 < 17:
    print("下午好！")
else:
    print("晚上好！")

